import { useState, useMemo } from "react";
import { useApp } from "../context/AppContext";
import { checkAvailabilityAPI, confirmBookingAPI } from "../services/api";
import Button from "../components/Button";
import Input from "../components/Input";

export default function RoomDetailPage() {
  const { state, dispatch } = useApp();
  const room = state.selectedRoom;

  const today = new Date().toISOString().split("T")[0];

  const [dates, setDates] = useState({ checkIn: today, checkOut: "" });
  const [errors, setErrors] = useState({});
  const [checking, setChecking] = useState(false);
  const [availability, setAvailability] = useState(null); // null | 'available' | 'unavailable'
  const [confirming, setConfirming] = useState(false);

  const nights = useMemo(() => {
    if (!dates.checkIn || !dates.checkOut) return 0;
    const diff = (new Date(dates.checkOut) - new Date(dates.checkIn)) / 86400000;
    return diff > 0 ? diff : 0;
  }, [dates]);

  const total = nights * room.price;

  const validate = () => {
    const e = {};
    if (!dates.checkIn) e.checkIn = "Select check-in date";
    if (!dates.checkOut) e.checkOut = "Select check-out date";
    if (dates.checkIn && dates.checkOut && dates.checkOut <= dates.checkIn)
      e.checkOut = "Check-out must be after check-in";
    if (dates.checkIn < today) e.checkIn = "Cannot select a past date";
    return e;
  };

  const handleDateChange = (e) => {
    setDates((d) => ({ ...d, [e.target.name]: e.target.value }));
    setAvailability(null);
    setErrors((err) => ({ ...err, [e.target.name]: "" }));
  };

  const handleCheckAvailability = async () => {
    const e = validate();
    if (Object.keys(e).length) { setErrors(e); return; }
    setErrors({});
    setChecking(true);
    setAvailability(null);
    try {
      const result = await checkAvailabilityAPI(
        room.id, dates.checkIn, dates.checkOut, state.bookings
      );
      setAvailability(result.available ? "available" : "unavailable");
    } catch {
      dispatch({ type: "SET_NOTIFICATION", payload: { type: "error", msg: "Failed to check availability. Try again." } });
    } finally {
      setChecking(false);
    }
  };

  const handleConfirmBooking = async () => {
    setConfirming(true);
    try {
      await confirmBookingAPI({ roomId: room.id, ...dates });
      dispatch({
        type: "ADD_BOOKING",
        payload: {
          id: Date.now(),
          roomId: room.id,
          roomName: room.name,
          roomImage: room.image,
          roomType: room.type,
          checkIn: dates.checkIn,
          checkOut: dates.checkOut,
          nights,
          total,
          bookedAt: new Date().toLocaleDateString("en-IN"),
        },
      });
    } catch {
      dispatch({ type: "SET_NOTIFICATION", payload: { type: "error", msg: "Booking failed. Please try again." } });
      setConfirming(false);
    }
  };

  return (
    <div className="page-wrap">
      <button
        className="btn btn-ghost"
        style={{ marginBottom: 24 }}
        onClick={() => dispatch({ type: "SET_PAGE", payload: "dashboard" })}
      >
        ← Back to Rooms
      </button>

      <div style={styles.layout}>
        {/* Left: Room Info */}
        <div>
          <div style={styles.hero}>{room.image}</div>
          <div style={styles.type}>{room.type}</div>
          <h1 style={styles.name}>{room.name}</h1>

          <div style={styles.infoGrid}>
            <div style={styles.infoItem}>
              <div style={styles.infoLabel}>Price per night</div>
              <div style={styles.infoValue}>₹{room.price.toLocaleString()}</div>
            </div>
            <div style={styles.infoItem}>
              <div style={styles.infoLabel}>Capacity</div>
              <div style={styles.infoValue}>{room.capacity} {room.capacity > 1 ? "guests" : "guest"}</div>
            </div>
          </div>

          <div style={styles.amenLabel}>Amenities</div>
          <div style={styles.amenities}>
            {room.amenities.map((a) => (
              <span key={a} style={styles.amenTag}>{a}</span>
            ))}
          </div>
        </div>

        {/* Right: Booking Panel */}
        <div style={styles.panel}>
          <h3 style={styles.panelTitle}>Reserve This Room</h3>

          <div style={styles.priceBox}>
            <div style={styles.bigPrice}>₹{room.price.toLocaleString()}</div>
            <div style={{ fontSize: 12, color: "var(--muted)" }}>per night</div>
          </div>

          <Input
            label="Check-in Date"
            type="date"
            name="checkIn"
            value={dates.checkIn}
            min={today}
            onChange={handleDateChange}
            error={errors.checkIn}
          />
          <Input
            label="Check-out Date"
            type="date"
            name="checkOut"
            value={dates.checkOut}
            min={dates.checkIn || today}
            onChange={handleDateChange}
            error={errors.checkOut}
          />

          {nights > 0 && (
            <div style={styles.totalRow}>
              <span style={{ fontSize: 13, color: "var(--muted)" }}>
                {nights} night{nights > 1 ? "s" : ""} × ₹{room.price.toLocaleString()}
              </span>
              <span style={{ fontFamily: "'Cormorant Garamond', serif", fontSize: 20, fontWeight: 600 }}>
                ₹{total.toLocaleString()}
              </span>
            </div>
          )}

          {availability && (
            <div className={`avail-badge ${availability === "available" ? "avail-yes" : "avail-no"}`}>
              {availability === "available" ? "✓ Room is available!" : "✗ Not available for selected dates"}
            </div>
          )}

          {availability !== "available" && (
            <Button variant="outline" fullWidth loading={checking} onClick={handleCheckAvailability}>
              Check Availability
            </Button>
          )}

          {availability === "available" && (
            <Button
              variant="gold"
              fullWidth
              loading={confirming}
              onClick={handleConfirmBooking}
              style={{ marginTop: 8 }}
            >
              Confirm Booking →
            </Button>
          )}
        </div>
      </div>
    </div>
  );
}

const styles = {
  layout: { display: "grid", gridTemplateColumns: "1fr 360px", gap: 48, alignItems: "start" },
  hero: { height: 280, background: "var(--warm)", borderRadius: 8, display: "flex", alignItems: "center", justifyContent: "center", fontSize: 96, marginBottom: 32, border: "1px solid var(--border)" },
  type: { fontSize: 11, letterSpacing: "0.2em", textTransform: "uppercase", color: "var(--gold)", marginBottom: 8 },
  name: { fontFamily: "'Cormorant Garamond', serif", fontSize: 44, fontWeight: 300, marginBottom: 24 },
  infoGrid: { display: "grid", gridTemplateColumns: "1fr 1fr", gap: 16, marginBottom: 32 },
  infoItem: { background: "var(--warm)", borderRadius: "var(--radius)", padding: 16 },
  infoLabel: { fontSize: 10, letterSpacing: "0.15em", textTransform: "uppercase", color: "var(--muted)", marginBottom: 6 },
  infoValue: { fontFamily: "'Cormorant Garamond', serif", fontSize: 20 },
  amenLabel: { fontSize: 11, letterSpacing: "0.15em", textTransform: "uppercase", color: "var(--muted)", marginBottom: 12 },
  amenities: { display: "flex", flexWrap: "wrap", gap: 8 },
  amenTag: { fontSize: 13, padding: "6px 12px", background: "var(--warm)", border: "1px solid var(--border)", borderRadius: 20, color: "var(--muted)" },
  panel: { background: "var(--surface)", border: "1px solid var(--border)", borderRadius: 8, padding: 32, position: "sticky", top: 80 },
  panelTitle: { fontFamily: "'Cormorant Garamond', serif", fontSize: 26, fontWeight: 300, marginBottom: 24 },
  priceBox: { textAlign: "center", padding: 20, background: "var(--warm)", borderRadius: "var(--radius)", marginBottom: 24 },
  bigPrice: { fontFamily: "'Cormorant Garamond', serif", fontSize: 42, fontWeight: 300 },
  totalRow: { display: "flex", justifyContent: "space-between", alignItems: "center", padding: "12px 0", borderTop: "1px solid var(--border)", marginBottom: 16 },
};
